2104       continue;
2105 
2106     auto *TrueSuccessor = BI->getSuccessor(0);
2107     auto *FalseSuccessor = BI->getSuccessor(1);
2108 
2109     auto DominatesNarrowUser = [this, NarrowUser] (BasicBlockEdge BBE) {
2110       return BBE.isSingleEdge() &&
2111              DT->dominates(BBE, NarrowUser->getParent());
2112     };
2113 
2114     if (DominatesNarrowUser(BasicBlockEdge(BB, TrueSuccessor)))
2115       UpdateRangeFromCondition(BI->getCondition(), /*TrueDest=*/true);
2116 
2117     if (DominatesNarrowUser(BasicBlockEdge(BB, FalseSuccessor)))
2118       UpdateRangeFromCondition(BI->getCondition(), /*TrueDest=*/false);
2119   }
2120 }
2121 
2122 /// Calculates PostIncRangeInfos map for the given IV
2123 void WidenIV::calculatePostIncRanges(PHINode *OrigPhi) {
2124   SmallPtrSet<Instruction *, 16> Visited;
2125   SmallVector<Instruction *, 6> Worklist;
2126   Worklist.push_back(OrigPhi);
2127   Visited.insert(OrigPhi);
2128 
2129   while (!Worklist.empty()) {
2130     Instruction *NarrowDef = Worklist.pop_back_val();
2131 
2132     for (Use &U : NarrowDef->uses()) {
2133       auto *NarrowUser = cast<Instruction>(U.getUser());
2134 
2135       // Don't go looking outside the current loop.
2136       auto *NarrowUserLoop = (*LI)[NarrowUser->getParent()];
2137       if (!NarrowUserLoop || !L->contains(NarrowUserLoop))
2138         continue;
2139 
2140       if (!Visited.insert(NarrowUser).second)
2141         continue;
2142 
2143       Worklist.push_back(NarrowUser);
2144 
2145       calculatePostIncRange(NarrowDef, NarrowUser);
2146     }
2147   }
2148 }
2149 
2150 PHINode *llvm::createWideIV(const WideIVInfo &WI,
2151     LoopInfo *LI, ScalarEvolution *SE, SCEVExpander &Rewriter,
2152     DominatorTree *DT, SmallVectorImpl<WeakTrackingVH> &DeadInsts,
2153     unsigned &NumElimExt, unsigned &NumWidened,
2154     bool HasGuards, bool UsePostIncrementRanges) {
2155   WidenIV Widener(WI, LI, SE, DT, DeadInsts, HasGuards, UsePostIncrementRanges);
2156   PHINode *WidePHI = Widener.createWideIV(Rewriter);
2157   NumElimExt = Widener.getNumElimExt();
2158   NumWidened = Widener.getNumWidened();
2159   return WidePHI;
